<template>
  <div class="Diary">
    <Nav></Nav>
    <div class="diary-main">
      <el-timeline :reverse="true">
        <el-timeline-item timestamp="2018/4/12" placement="top"
                          v-for="(item, index) in diaryArr"
                          :key="index"
                          :color="item.color"
                          :timestamp="item.date"
        >
          <el-card>
            <h3 v-if="!!item.title">{{item.title}}</h3>
            <p>{{item.txt}}</p>
            <el-image
                v-for="(i,ind) in item.img"
                :src="i"
                :preview-src-list="item.img"
                :z-index="2020"
                :alt="item.title?item.title:item.content"
                :key="ind"
            >
            </el-image>
          </el-card>
        </el-timeline-item>
      </el-timeline>
    </div>
    <bottomFooter></bottomFooter>
  </div>
</template>

<script>
  import Nav from "../../components/Nav";
  import bottomFooter from "../../components/bottomFooter";
  //axios
  import axiosApi from '../../api/index'
  let getDiaryList = axiosApi.getDiaryList;//获取时间轴

  export default {
    name: "Diary",
    components:{
      Nav,
      bottomFooter
    },
    data(){
      return {
        diaryArr:[]
      }
    },
    created() {
      getDiaryList()
        .then(data=>{
          if (data.data.code) {
            this.$message.error({message:data.data.msg});
            return
          }
          let dataList = data.data.data;
          this.diaryArr = JSON.parse(JSON.stringify(dataList));
          this.diaryArr = this.diaryArr.map(item=>{
            let date = item.date;
            item.date = ''+new Date(date).getFullYear()+'-'+(new Date(date).getMonth() +1)+'-'+new Date(date).getDate();
            return item
          });
        })
    }
  }
</script>

<style scoped lang="less">
 .diary-main{
   max-width: 1260px;
   min-height:518px;
   margin: 0 auto;
   padding: 100px 10px 15px;
   >.el-timeline{
     padding: 40px 15px 20px 70px;
     background-color: rgba(255,255,255,0.1);
     border-radius: 20px;
     box-shadow: 0 0 10px 1px;
     /deep/.el-timeline-item__timestamp{
       color: #fff;
     }
     .el-timeline-item{
       .el-card{
         p{
           font-size: 18px;
           padding-bottom: 5px;
         }
         .el-image{
           display: block;
           margin-bottom: 10px;
         }
         /deep/img{
           width: 500px;
         }
       }
     }
   }
 }
  /deep/.el-image-viewer__close{
    color: red;
  }
</style>